const now = new Date();

// 獲取 GMT+8 時區的時間
const options = { timeZone: 'Asia/Hong_Kong', hour12: false };
const formatter = new Intl.DateTimeFormat('en-US', options);

// 獲取 GMT+8 時間的各個組件
const localDate = new Date(now.toLocaleString("en-US", { timeZone: "Asia/Hong_Kong" }));

localDate.setHours(localDate.getHours());

// 格式化為 yyyy-MM-dd hh:mm:ss
const year = localDate.getFullYear();
const month = String(localDate.getMonth() + 1).padStart(2, '0'); // 月份從 0 開始
const day = String(localDate.getDate()).padStart(2, '0');
//const hours = String(localDate.getHours()).padStart(2, '0');
//const minutes = String(localDate.getMinutes()).padStart(2, '0');

const currentDateTime = `${year}-${month}-${day}`;

return [{ json: { currentDateTime } }];

