// Input data is assumed to be in the items array
const inputData = $input.first().json.data;

// 假设 phone 数据在另一个变量中
const phoneData = $('Breakdown each phone number').all();
const phoneNumbers = phoneData.map(item => item.json.phone);

const output = [];
const conversationMap = {}; // 用於跟踪每個 conversationId 的狀態
let phoneIndex = 0; // 用於跟踪電話索引

inputData.forEach(entry => {
  // Check if the messages object and items array exist
  if (entry.messages && Array.isArray(entry.messages.items)) {
    // Map over the items to extract the created field and current time
    entry.messages.items.forEach(item => {
      // 獲取當前的 conversationId
      const conversationId = item.conversationId;

      // 如果 operatorName 為 null 且尚未處理過該 conversationId
      if (item.operatorName === null && !conversationMap[conversationId]) {
        // 確保電話索引不超出範圍
        if (phoneIndex < phoneNumbers.length) {
          output.push({
            created: item.created, // Extract the created field
            currentTimeGMT: new Date().toISOString(), // Get the current time in GMT
            conversationId: conversationId, // Add conversationId
            phone: phoneNumbers[phoneIndex] // Add corresponding phone number
          });
          phoneIndex++; // Increment phone index
        }
        // 標記該 conversationId 已處理
        conversationMap[conversationId] = true;
      }
    });
  }
});

// Return the output
return output.map(item => ({ json: item }));

// 獲取所有輸入數據
