// 獲取輸入的數據
const inputData = $input.first().json.data; // 獲取 online 訊息的數據
const phoneData = $('EIHL Sales Phone number List').first().json.data;
const nameData = $('Name JSON').all(); // 確保這裡正確引用

// 輸出 nameData 以進行調試
console.log('Name Data:', JSON.stringify(nameData, null, 2)); // 調試輸出

// 創建一個字典映射 conversationId 到 phone
const phoneMap = {};
phoneData.forEach(item => {
  if (item.phone && item.conversationId) {
    phoneMap[item.conversationId] = item.phone; // 映射 conversationId 到 phone
  }
});

// 輸出 phoneMap 以進行調試
console.log('Phone Map:', phoneMap);

// 創建一個字典映射 phone 到 fullName
const nameMap = {};
nameData.forEach(item => {
  if (item.contact_list && Array.isArray(item.contact_list)) {
    item.contact_list.forEach(contact => {
      if (contact.phone && contact.fullName) { // 確保 phone 和 fullName 都存在
        const trimmedPhone = contact.phone.trim(); // 去除前後空格
        nameMap[trimmedPhone] = contact.fullName; // 映射 phone 到 fullName
      } else {
        console.log(`Missing phone or fullName in contact:`, contact); // 檢查缺失的數據
      }
    });
  } else {
    console.log(`No contact_list found in item:`, item); // 檢查沒有聯繫人列表的項目
  }
});

// 輸出 nameMap 以進行調試
console.log('Name Map:', nameMap);

const onlineRecords = []; // 用於存儲每個 conversationId 的最近在線時間

// 遍歷每一個 entry
inputData.forEach(entry => {
  let conversationId = null;
  let latestOnlineTime = null; // 用於存儲最近的 created 時間

  // 檢查 messages 對象和 items 陣列是否存在
  if (entry.messages && Array.isArray(entry.messages.items)) {
    // 遍歷所有 message items
    for (const item of entry.messages.items) {
      // 檢查 text 是否為 "Online"
      if (item.text === "Online") {
        // 更新最近的 created 時間
        if (!latestOnlineTime || new Date(item.created) > new Date(latestOnlineTime)) {
          latestOnlineTime = item.created; // 保持最近的 created 時間
          conversationId = item.conversationId; // 取得對應的 conversationId
        }
      }
    }
  }

  // 如果找到最新的在線時間，將其記錄下來
  if (latestOnlineTime && conversationId) {
    const phone = phoneMap[conversationId] || null; // 根據 conversationId 獲取對應的 phone
    const trimmedPhone = phone ? phone.trim() : null; // 去除 phone 的前後空格
    const fullName = trimmedPhone ? nameMap[trimmedPhone] || 'N/A' : 'N/A'; // 根據 phone 獲取對應的 fullName

    // 輸出調試信息
    console.log(`Conversation ID: ${conversationId}, Phone: ${trimmedPhone}, Full Name: ${fullName}`);

    onlineRecords.push({
      conversationId: conversationId, // 保存 conversationId
      latest_created: latestOnlineTime, // 保存最近的 created 時間
      phone: trimmedPhone // 保存電話號碼
      //fullName: fullName // 保存姓名
    });
  }
});

// 返回所有的在線記錄，包裝在一個物件中
return [{ json: { onlineRecords } }];

